CREATE TEMPORARY TABLE `tmp_creature_faction_rank1` (
  `entry` int unsigned NOT NULL,
  `faction` smallint unsigned NOT NULL,
  PRIMARY KEY (`entry`)
) ENGINE=Memory;


UPDATE `creature_template` AS ct
INNER JOIN `tmp_creature_faction_rank1` AS t ON ct.`entry` = t.`entry`
SET ct.`faction` = t.`faction`;

